catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading)
        return;

    g_form.clearOptions('job_role');

    switch (newValue) {

        case 'operations':
            g_form.addOption('job_role', 'operations_executive', 'Operations Executive');
            break;

        case 'marketing':
            g_form.addOption('job_role', 'marketing_executive', 'Marketing Executive');
            break;

        case 'hr':
            g_form.addOption('job_role', 'hr_executive', 'HR Executive');
            break;

        case 'it':
            g_form.addOption('job_role', 'software_developer', 'Software Developer');
            break;

        case 'sales':
            g_form.addOption('job_role', 'sales_executive', 'Sales Executive');
            break;

        case 'finance':
            g_form.addOption('job_role', 'accountant', 'Accountant');
            break;
    }

}
